  `return_type` tinyint NULL DEFAULT NULL COMMENT '计划还款方式',
  `price` decimal(24, 6) NOT NULL COMMENT '计划回款金额',
  `remind_days` bigint NULL DEFAULT NULL COMMENT '提前几天提醒',
  `remind_time` datetime NULL DEFAULT NULL COMMENT '提醒日期',
