INSERT INTO `ai_music` VALUES (1, 1, '幸福的旋律', '[Verse]\n阳光撒满了街道\n梦想在心中起跑\n[Verse 2]\n快乐随着风在笑\n青春在时光里跳\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好\n[Verse 3]\n花开在晨曦微笑\n心跳伴随音符跳\n[Bridge]\n让烦恼都退烧\n世界只剩心跳\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好', 'https://cdn1.suno.ai/image_73032eee-470e-46ff-a9bd-abb3e67b2934.png', 'http://test.litchi.iocoder.cn/12f3702f71bf3d1e7eadbc0d611afca58868b783fe9c8b30bf913b4aa74e3af1.mp3', 'https://cdn1.suno.ai/73032eee-470e-46ff-a9bd-abb3e67b2934.mp4', 20, '来一首快乐的歌曲', '[Verse]\n阳光撒满了街道\n梦想在心中起跑\n\n[Verse 2]\n快乐随着风在笑\n青春在时光里跳\n\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好\n\n[Verse 3]\n花开在晨曦微笑\n心跳伴随音符跳\n\n[Bridge]\n让烦恼都退烧\n世界只剩心跳\n\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好', 'Suno', 0, 'chirp-v3.5', 2, '[\"pop\"]', 145.96, b'0', '73032eee-470e-46ff-a9bd-abb3e67b2934', NULL, '1', '2024-06-27 21:08:42', '1', '2024-07-05 01:30:16', b'0', 1);
