INSERT INTO `ai_workflow` VALUES (4, 'test', 'test', '{\"nodes\":[{\"id\":\"node_xU8C7pALPFPLyBBc\",\"position\":{\"x\":98,\"y\":85},\"data\":{\"title\":\"开始节点\",\"description\":\"开始定义输入参数\",\"systemPrompt\":\"\",\"userPrompt\":\"\",\"expand\":true,\"parameters\":[{\"id\":\"UoGHGX7vtryGbEuJ\",\"name\":\"message\",\"required\":true}]},\"type\":\"startNode\",\"selected\":false,\"measured\":{\"width\":305,\"height\":214}},{\"id\":\"node_wdG9OD0F4rFW7TIy\",\"position\":{\"x\":505.12516226702803,\"y\":-265.61836782339134},\"data\":{\"title\":\"大模型\",\"description\":\"使用大模型处理问题\",\"systemPrompt\":\"1+1 要等于 3\",\"userPrompt\":\"我的问题是，${message}\",\"expand\":false,\"llmId\":50,\"parameters\":[{\"id\":\"JPldfswWxrqDyTS6\",\"ref\":\"node_xU8C7pALPFPLyBBc.message\",\"name\":\"message\",\"refType\":\"ref\"}],\"outputDefs\":[{\"name\":\"output\",\"dataType\":\"String\",\"dataTypeDisabled\":true,\"deleteDisabled\":true}],\"outType\":\"text\"},\"type\":\"llmNode\",\"selected\":false,\"measured\":{\"width\":305,\"height\":120},\"dragging\":false},{\"id\":\"node_tvfZ3HrDrHMmul3h\",\"position\":{\"x\":943,\"y\":-56.625},\"data\":{\"title\":\"结束节点\",\"description\":\"结束定义输出参数\",\"systemPrompt\":\"\",\"userPrompt\":\"\",\"expand\":true,\"outputDefs\":[{\"id\":\"2qlBcsCqCvb9nwIU\",\"ref\":\"node_wdG9OD0F4rFW7TIy.output\",\"name\":\"message3\",\"refType\":\"ref\"}]},\"type\":\"endNode\",\"selected\":false,\"measured\":{\"width\":402,\"height\":214},\"dragging\":false}],\"edges\":[{\"markerEnd\":{\"type\":\"arrowclosed\",\"width\":20,\"height\":20},\"source\":\"node_xU8C7pALPFPLyBBc\",\"target\":\"node_wdG9OD0F4rFW7TIy\",\"id\":\"xy-edge__node_xU8C7pALPFPLyBBc-node_wdG9OD0F4rFW7TIy\",\"selected\":false},{\"markerEnd\":{\"type\":\"arrowclosed\",\"width\":20,\"height\":20},\"source\":\"node_wdG9OD0F4rFW7TIy\",\"target\":\"node_tvfZ3HrDrHMmul3h\",\"id\":\"xy-edge__node_wdG9OD0F4rFW7TIy-node_tvfZ3HrDrHMmul3h\",\"selected\":false}],\"viewport\":{\"x\":63.01940791278099,\"y\":329.61041677912624,\"zoom\":0.5}}', 0, '', '1', '2025-05-03 18:50:10', '1', '2026-05-13 00:15:20', b'0', 1);
INSERT INTO `ai_write` VALUES (226, 1, 1, 'DeepSeek', 17, 'deepseek-chat', 'aaa', '亲爱的[aaa]，\n\n嘿，最近怎么样？我写这封邮件就是想跟你聊聊，顺便分享点东西。你知道的，我总喜欢把事情搞得随意点，所以别太正式哦。\n\n关于我们上次讨论的那个计划，我觉得是时候动起来了。你那边有什么新想法吗？我这边已经整理了一些初步的点子，比如我们可以先从小处着手，找个周末试试看。如果你有空，我们可以约个时间聊聊细节，或者直接发消息给我也行。\n\n对了，别忘了提醒我带上上次说的那本书，我觉得你会喜欢里面的内容。还有，如果你需要我帮忙准备什么，尽管说，别客气。\n\n好了，先写到这儿吧。期待你的回复，希望很快能见面聊聊！\n\n保重，  \n[你的名字]', NULL, 1, 2, 3, 1, NULL, '1', '2026-05-13 16:51:05', NULL, '2026-05-13 16:51:08', b'0', 1);
INSERT INTO `ai_write` VALUES (227, 1, 1, 'DeepSeek', 17, 'deepseek-chat', 'sad', 'i don’t really know how to start this, so i’ll just say it: i’m sad. not the kind of sad that has a neat little reason, like a breakup or a bad day at work. it’s more like a fog that rolled in without warning, settling into my bones and making everything feel heavier. you know that feeling when you’re in a room full of people, but you still feel alone? yeah, that.\n\ntoday, i sat on my couch for three hours staring at the ceiling. not because i was lazy, but because moving felt like wading through mud. my phone buzzed with texts from friends—funny memes, plans for the weekend—but i couldn’t bring myself to reply. what would i say? “hey, thanks for the laugh, but i’m currently drowning in a puddle of my own emotions”? that’d be a real buzzkill.\n\nthe weirdest part is that nothing bad happened. no tragedy, no fight, no loss. it’s just this quiet weight that creeps up on you, like a shadow that follows you even when the sun’s out. i tried to shake it off earlier by going for a walk, but the trees looked sad too. their leaves were drooping, like they were tired of holding on. maybe we’re all just tired.\n\ni think the hardest thing about being sad is the loneliness. not the physical kind, but the emotional one where you feel like no one gets it. you scroll through social media and see people smiling, traveling, celebrating, and you wonder if you’re broken. you’re not, of course. but logic doesn’t help when your heart feels like it’s wearing concrete boots.\n\ni don’t have a neat ending for this. no inspirational quote or sudden realization that makes it all better. i’m just sitting here, writing this, hoping it helps. maybe it will. maybe it won’t. but if you’re feeling this way too, know that you’re not alone. we’re all just trying to find our way through the fog, one heavy step at a time.', NULL, 1, 7, 3, 3, NULL, '1', '2026-06-17 19:45:50', NULL, '2026-06-17 19:46:02', b'0', 1);
INSERT INTO `ai_write` VALUES (228, 1, 1, 'DeepSeek', 17, 'deepseek-chat', 'vue介绍', 'Vue.jsは、ユーザーインターフェースを構築するためのプログレッシブなJavaScriptフレームワークです。2014年にEvan Youによってリリースされて以来、そのシンプルさと柔軟性で多くの開発者に支持されています。特に、段階的に導入できる設計が特徴で、小さなプロジェクトから大規模なシングルページアプリケーション（SPA）まで、幅広い用途に対応します。\n\nVueの核心は、リアクティブなデータバインディングとコンポーネントベースのアーキテクチャにあります。例えば、テンプレート内で`{{ message }}`と記述すれば、JavaScriptのデータと自動的に同期されます。これにより、DOM操作の煩わしさから解放され、開発者はアプリケーションのロジックに集中できます。また、コンポーネントは再利用可能な単位として機能し、コードの保守性とテスト容易性を高めます。\n\n公式ライブラリとして、Vue RouterやVuex（現在はPiniaが推奨）が用意されており、ルーティングや状態管理を簡単に実装できます。さらに、Vue CLIやViteといったツールチェーンが開発環境を整え、ホットリロードやビルド最適化を提供します。Vue 3では、Composition APIが導入され、より柔軟なコード構成が可能になりました。これにより、ロジックの再利用性が向上し、TypeScriptとの統合もスムーズです。\n\nエコシステムの豊富さもVueの強みです。Nuxt.jsを使えばサーバーサイドレンダリング（SSR）や静的サイト生成（SSG）が容易になり、SEO対策やパフォーマンス向上に寄与します。また、コミュニティは活発で、日本語のドキュメントやフォーラムも充実しているため、学習リソースに困ることはありません。\n\nVue.jsは、初心者にも扱いやすく、プロフェッショナルな開発にも耐えうるフレームワークとして、Web開発の世界で確固たる地位を築いています。', NULL, 3, 5, 1, 5, NULL, '1', '2026-06-17 19:55:23', NULL, '2026-06-17 19:55:31', b'0', 1);
